b1=A.c5('<!DOCTYPE html>\n<html lang="en">\n<head>\n  <meta charset="UTF-8" />\n  <meta name="viewport" content="width=device-width, initial-scale=1.0" />\n  <title>Department of Computing & Mathematics</title>\n  <link href="https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;700;900&family=DM+Sans:wght@300;400;500&display=swap" rel="stylesheet" />\n  <style>\n    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n\n    :root {\n      --navy: #0d1b2a;\n      --gold: #c9a84c;\n      --gold-light: #e8c97a;\n      --cream: #f5f0e8;\n      --warm-white: #fdfaf5;\n      --text: #1a1a2e;\n      --muted: #6b6b80;\n      --nav-h: 68px;\n    }\n\n    html { scroll-behavior: smooth; }\n\n    body {\n      font-family: \'DM Sans\', sans-serif;\n      background: var(--warm-white);\n      color: var(--text);\n      overflow-x: hidden;\n    }\n\n    /* \u2500\u2500 NAVBAR \u2500\u2500 */\n    nav {\n      position: fixed;\n      top: 0; left: 0; right: 0;\n      height: var(--nav-h);\n      background: var(--navy);\n      display: flex;\n      align-items: center;\n      justify-content: space-between;\n      padding: 0 48px;\n      z-index: 1000;\n      box-shadow: 0 2px 24px rgba(0,0,0,0.3);\n    }\n\n    .nav-brand {\n      font-family: \'Playfair Display\', serif;\n      font-size: 1.15rem;\n      color: var(--gold);\n      letter-spacing: 0.02em;\n      white-space: nowrap;\n    }\n\n    .nav-menus {\n      display: flex;\n      gap: 8px;\n      list-style: none;\n    }\n\n    .nav-menus > li {\n      position: relative;\n    }\n\n    .nav-menus > li > a {\n      display: flex;\n      align-items: center;\n      gap: 6px;\n      padding: 10px 18px;\n      color: #c8d0e0;\n      text-decoration: none;\n      font-size: 0.875rem;\n      font-weight: 500;\n      letter-spacing: 0.06em;\n      text-transform: uppercase;\n      border-radius: 4px;\n      transition: color 0.2s, background 0.2s;\n    }\n\n    .nav-menus > li > a::after {\n      content: \'\u25be\';\n      font-size: 0.75rem;\n      opacity: 0.6;\n      transition: transform 0.2s;\n    }\n\n    .nav-menus > li:hover > a {\n      color: var(--gold-light);\n      background: rgba(255,255,255,0.07);\n    }\n\n    .nav-menus > li:hover > a::after {\n      transform: rotate(-180deg);\n    }\n\n    /* \u2500\u2500 Regular Dropdown (Academics & Labs) \u2500\u2500 */\n    .dropdown {\n      position: absolute;\n      top: calc(100% + 8px);\n      left: 0;\n      background: #fff;\n      border: 1px solid #e0dbd0;\n      border-radius: 8px;\n      box-shadow: 0 12px 40px rgba(0,0,0,0.12);\n      min-width: 220px;\n      opacity: 0;\n      visibility: hidden;\n      transform: translateY(-6px);\n      transition: opacity 0.2s, transform 0.2s, visibility 0.2s;\n      overflow: hidden;\n    }\n\n    .nav-menus > li:hover .dropdown {\n      opacity: 1;\n      visibility: visible;\n      transform: translateY(0);\n    }\n\n    .dropdown a {\n      display: block;\n      padding: 12px 20px;\n      color: var(--text);\n      text-decoration: none;\n      font-size: 0.88rem;\n      font-weight: 400;\n      border-bottom: 1px solid #f0ece4;\n      transition: background 0.15s, color 0.15s, padding-left 0.15s;\n    }\n\n    .dropdown a:last-child { border-bottom: none; }\n\n    .dropdown a:hover {\n      background: var(--cream);\n      color: var(--navy);\n      padding-left: 28px;\n    }\n\n    .dropdown a span {\n      display: inline-block;\n      width: 6px; height: 6px;\n      background: var(--gold);\n      border-radius: 50%;\n      margin-right: 10px;\n      vertical-align: middle;\n    }\n\n    /* \u2500\u2500 Mega Menu (Programmes) \u2500\u2500 */\n    .nav-menus > li.has-mega {\n      position: static; /* so mega is positioned relative to the nav bar */\n    }\n\n    .mega-menu {\n      position: absolute;\n      top: 100%;\n      right: 0;\n      background: #fff;\n      border-top: 3px solid var(--gold);\n      box-shadow: 0 16px 48px rgba(0,0,0,0.14);\n      opacity: 0;\n      visibility: hidden;\n      transform: translateY(-6px);\n      transition: opacity 0.22s, transform 0.22s, visibility 0.22s;\n      z-index: 999;\n    }\n\n    .nav-menus > li.has-mega:hover .mega-menu {\n      opacity: 1;\n      visibility: visible;\n      transform: translateY(0);\n    }\n\n    .mega-inner {\n      display: grid;\n      grid-template-columns: repeat(4, 1fr);\n      gap: 0;\n      max-width: 1300px;\n      margin: 0 auto;\n      padding: 32px 48px;\n    }\n\n    .mega-col {\n      padding: 0 24px;\n      border-right: 1px solid #ede9e0;\n    }\n\n    .mega-col:first-child { padding-left: 0; }\n    .mega-col:last-child  { padding-right: 0; border-right: none; }\n\n    .mega-col-title {\n      font-family: \'Playfair Display\', serif;\n      font-size: 0.78rem;\n      font-weight: 700;\n      letter-spacing: 0.14em;\n      text-transform: uppercase;\n      color: var(--gold);\n      margin-bottom: 14px;\n      padding-bottom: 10px;\n      border-bottom: 1px solid var(--cream);\n    }\n\n    .mega-col a {\n      display: flex;\n      align-items: center;\n      gap: 8px;\n      padding: 7px 0;\n      color: var(--text);\n      text-decoration: none;\n      font-size: 0.85rem;\n      border-bottom: 1px solid #f5f2ec;\n      transition: color 0.15s, gap 0.15s;\n    }\n\n    .mega-col a:last-child { border-bottom: none; }\n\n    .mega-col a::before {\n      content: \'\';\n      display: inline-block;\n      width: 5px; height: 5px;\n      border-radius: 50%;\n      background: var(--gold);\n      opacity: 0.4;\n      flex-shrink: 0;\n      transition: opacity 0.15s;\n    }\n\n    .mega-col a:hover {\n      color: var(--navy);\n      gap: 12px;\n    }\n\n    .mega-col a:hover::before {\n      opacity: 1;\n    }\n\n    .mega-footer {\n      background: var(--cream);\n      padding: 12px 48px;\n      display: flex;\n      align-items: center;\n      justify-content: space-between;\n      font-size: 0.8rem;\n      color: var(--muted);\n    }\n\n    .mega-footer a {\n      color: var(--navy);\n      text-decoration: none;\n      font-weight: 600;\n      font-size: 0.8rem;\n      letter-spacing: 0.05em;\n    }\n\n    .mega-footer a:hover { color: var(--gold); }\n\n    /* \u2500\u2500 HERO \u2500\u2500 */\n    .hero {\n      margin-top: var(--nav-h);\n      background: var(--navy);\n      padding: 80px 80px 70px;\n      position: relative;\n      overflow: hidden;\n    }\n\n    .hero::before {\n      content: \'\';\n      position: absolute;\n      top: -60px; right: -60px;\n      width: 420px; height: 420px;\n      border: 80px solid rgba(201,168,76,0.08);\n      border-radius: 50%;\n    }\n\n    .hero::after {\n      content: \'\';\n      position: absolute;\n      bottom: -30px; right: 120px;\n      width: 200px; height: 200px;\n      border: 40px solid rgba(201,168,76,0.05);\n      border-radius: 50%;\n    }\n\n    .hero-label {\n      font-size: 0.78rem;\n      letter-spacing: 0.2em;\n      text-transform: uppercase;\n      color: var(--gold);\n      margin-bottom: 16px;\n    }\n\n    .hero h1 {\n      font-family: \'Playfair Display\', serif;\n      font-size: clamp(2.2rem, 4vw, 3.6rem);\n      font-weight: 900;\n      color: #fff;\n      line-height: 1.15;\n      max-width: 620px;\n    }\n\n    .hero h1 em {\n      font-style: normal;\n      color: var(--gold);\n    }\n\n    .hero p {\n      margin-top: 20px;\n      color: #9ba8be;\n      font-size: 1rem;\n      max-width: 500px;\n      line-height: 1.7;\n    }\n\n    /* \u2500\u2500 MAIN CONTENT \u2500\u2500 */\n    main {\n      max-width: 1100px;\n      margin: 0 auto;\n      padding: 0 48px 80px;\n    }\n\n    /* \u2500\u2500 SECTION \u2500\u2500 */\n    .section {\n      padding-top: 80px;\n    }\n\n    .section-header {\n      display: flex;\n      align-items: baseline;\n      gap: 20px;\n      margin-bottom: 40px;\n      border-bottom: 2px solid var(--cream);\n      padding-bottom: 20px;\n    }\n\n    .section-number {\n      font-family: \'Playfair Display\', serif;\n      font-size: 3rem;\n      font-weight: 900;\n      color: var(--gold);\n      opacity: 0.35;\n      line-height: 1;\n    }\n\n    .section-title {\n      font-family: \'Playfair Display\', serif;\n      font-size: 2rem;\n      font-weight: 700;\n      color: var(--navy);\n    }\n\n    /* \u2500\u2500 CARDS GRID \u2500\u2500 */\n    .cards {\n      display: grid;\n      grid-template-columns: 1fr;\n      gap: 24px;\n    }\n\n    .card {\n      background: #fff;\n      border: 1px solid #e8e4da;\n      border-radius: 10px;\n      padding: 28px 28px 24px;\n      transition: transform 0.2s, box-shadow 0.2s;\n      scroll-margin-top: calc(var(--nav-h) + 24px);\n    }\n\n    .card:hover {\n      transform: translateY(-4px);\n      box-shadow: 0 12px 32px rgba(13,27,42,0.09);\n    }\n\n    .card-tag {\n      display: inline-block;\n      font-size: 0.7rem;\n      letter-spacing: 0.15em;\n      text-transform: uppercase;\n      background: var(--cream);\n      color: var(--gold);\n      border-radius: 4px;\n      padding: 3px 10px;\n      margin-bottom: 14px;\n      font-weight: 600;\n    }\n\n    .card h3 {\n      font-family: \'Playfair Display\', serif;\n      font-size: 1.2rem;\n      font-weight: 700;\n      color: var(--navy);\n      margin-bottom: 10px;\n    }\n\n    .card p {\n      font-size: 0.875rem;\n      color: var(--muted);\n      line-height: 1.7;\n    }\n\n    .card-meta {\n      display: flex;\n      flex-wrap: wrap;\n      gap: 8px;\n      margin-top: 18px;\n    }\n\n    .badge {\n      font-size: 0.72rem;\n      background: #f0f4f8;\n      color: #4a5568;\n      border-radius: 4px;\n      padding: 3px 9px;\n    }\n\n    /* Academics specific */\n    .card.academic .card-avatar {\n      width: 44px; height: 44px;\n      background: var(--navy);\n      border-radius: 50%;\n      display: flex; align-items: center; justify-content: center;\n      color: var(--gold);\n      font-family: \'Playfair Display\', serif;\n      font-size: 1.1rem;\n      font-weight: 700;\n      margin-bottom: 14px;\n    }\n\n    /* Labs specific */\n    .card.lab .lab-icon {\n      font-size: 1.8rem;\n      margin-bottom: 12px;\n    }\n\n    /* \u2500\u2500 DIVIDER \u2500\u2500 */\n    .section-divider {\n      height: 1px;\n      background: linear-gradient(to right, var(--gold), transparent);\n      margin: 20px 0 0;\n      opacity: 0.3;\n    }\n\n    /* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n       ACADEMIC CARD \u2014 INNER CONTENT OVERHAUL\n    \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n\n    /* Workload section */\n    .card.academic > div > p {\n      font-size: 0.82rem;\n      color: var(--muted);\n      margin-bottom: 6px;\n    }\n\n    .card.academic > div > p:first-child {\n      font-size: 0.78rem;\n      letter-spacing: 0.08em;\n      text-transform: uppercase;\n      color: var(--gold);\n      font-weight: 600;\n      margin-bottom: 10px;\n    }\n\n    .card.academic > div > ul {\n      list-style: none;\n      background: var(--cream);\n      border-left: 3px solid var(--gold);\n      border-radius: 0 6px 6px 0;\n      padding: 10px 16px;\n      margin: 8px 0 14px;\n      display: flex;\n      flex-direction: column;\n      gap: 4px;\n    }\n\n    .card.academic > div > ul li {\n      font-size: 0.8rem;\n      color: var(--text);\n      line-height: 1.5;\n    }\n\n    .card.academic > div > ul li b {\n      color: var(--navy);\n    }\n\n    .card.academic > div > ul li[style*="color: red"] {\n      color: #c0392b !important;\n      font-weight: 600;\n    }\n\n    /* Timetable heading (the bold "Timetables (\u2026)" paragraph) */\n    .card.academic > div > p > b {\n      font-size: 0.78rem;\n      letter-spacing: 0.06em;\n      text-transform: uppercase;\n      color: var(--navy);\n      font-weight: 700;\n    }\n\n    /* "No Entries" italic */\n    .card.academic > div > p[style*="font-style: italic"],\n    .card.academic > div > p i {\n      font-size: 0.8rem;\n      color: var(--muted);\n      font-style: italic;\n    }\n\n    /* \u2500\u2500 Timetable table (shared: academic & programme cards) \u2500\u2500 */\n    .card table {\n      width: 100%;\n      border-collapse: collapse;\n      margin: 12px 0 20px;\n      border-radius: 8px;\n      overflow: hidden;\n      box-shadow: 0 1px 6px rgba(13,27,42,0.07);\n      font-size: 0.8rem;\n    }\n\n    /* Period label h3 inside an academic table (e.g. "Full Year") */\n    .card table h3 {\n      display: block;\n      font-family: \'Playfair Display\', serif;\n      font-size: 0.78rem;\n      font-weight: 700;\n      letter-spacing: 0.12em;\n      text-transform: uppercase;\n      color: var(--gold);\n      background: var(--navy);\n      padding: 7px 14px;\n    }\n\n    /* Programme card: the div>h3 title banner above the rows */\n    .card table div > h3:first-child {\n      font-family: \'Playfair Display\', serif;\n      font-size: 0.9rem;\n      font-weight: 700;\n      letter-spacing: 0.04em;\n      text-transform: none;\n      color: #fff;\n      background: var(--navy);\n      padding: 10px 16px;\n      display: block;\n      border-bottom: 2px solid var(--gold);\n    }\n\n    /* Standalone h3 outside table but inside academic card div */\n    .card.academic > div > h3 {\n      font-family: \'Playfair Display\', serif;\n      font-size: 0.78rem;\n      font-weight: 700;\n      letter-spacing: 0.12em;\n      text-transform: uppercase;\n      color: var(--muted);\n      background: var(--cream);\n      padding: 6px 14px;\n      border-radius: 4px;\n      margin: 10px 0 4px;\n    }\n\n    /* Header row */\n    .card table th {\n      background: var(--navy);\n      color: var(--gold-light);\n      font-family: \'DM Sans\', sans-serif;\n      font-size: 0.72rem;\n      font-weight: 600;\n      letter-spacing: 0.07em;\n      text-transform: uppercase;\n      padding: 9px 12px;\n      text-align: center;\n      border: none;\n      white-space: nowrap;\n    }\n\n    .card table th:first-child {\n      text-align: left;\n      min-width: 100px;\n      color: rgba(232,201,122,0.6);\n    }\n\n    /* Body rows */\n    .card table td {\n      padding: 7px 10px;\n      border: 1px solid #eee8dc;\n      text-align: center;\n      vertical-align: middle;\n      font-size: 0.78rem;\n      color: var(--muted);\n      background: #fff;\n      transition: background 0.15s;\n    }\n\n    /* Time column */\n    .card table td:first-child {\n      text-align: left;\n      font-size: 0.74rem;\n      color: var(--navy);\n      font-weight: 500;\n      background: #faf7f2 !important;\n      white-space: nowrap;\n      padding-left: 12px;\n      border-left: none;\n    }\n    .card table td:first-child i {\n      font-style: normal;\n    }\n\n    /* Alternating row tint */\n    .card table tr:nth-child(even) td:first-child {\n      background: #f3efe8 !important;\n    }\n\n    /* \u2500\u2500 Scheduled session cell (was bgcolor=#f0f0f0) \u2500\u2500 */\n    .card table td[bgcolor=\'#f0f0f0\'] {\n      background: linear-gradient(135deg, #e8f0e8, #d4e8d4) !important;\n      border: 1px solid #b8d4b8 !important;\n      font-weight: 700;\n      color: #2d5a2d;\n      font-size: 0.76rem;\n      letter-spacing: 0.03em;\n      cursor: default;\n    }\n\n    /* \u2500\u2500 Break / lunch cell (was bgcolor=#ffffc0) \u2500\u2500 */\n    .card table td[bgcolor=\'#ffffc0\'] {\n      background: #fdf8ec !important;\n      border-color: #ede6d0 !important;\n    }\n    .card table td[bgcolor=\'#ffffc0\']:first-child {\n      background: #f7f0d8 !important;\n    }\n\n    /* Programme cards that contain only a table \u2014 remove default card padding top */\n    .card:not(.academic):not(.lab) {\n      padding: 0;\n      overflow: hidden;\n    }\n\n    .card:not(.academic):not(.lab) > table {\n      margin: 0;\n    }\n\n    /* The scroll wrapper so wide tables don\'t break layout */\n    .card:not(.academic):not(.lab) {\n      overflow-x: auto;\n    }\n\n    /* \u2500\u2500 TOOLTIP \u2500\u2500 */\n    .tooltip {\n      position: relative;\n      display: block;\n      width: 100%;\n      height: 100%;\n    }\n\n    .tooltiptext {\n      visibility: hidden;\n      opacity: 0;\n      background: var(--navy);\n      color: #e0e8f4;\n      border-radius: 8px;\n      padding: 14px 16px;\n      position: absolute;\n      z-index: 200;\n      bottom: calc(100% + 8px);\n      left: 50%;\n      transform: translateX(-50%);\n      width: 240px;\n      box-shadow: 0 8px 28px rgba(0,0,0,0.22);\n      border: 1px solid rgba(201,168,76,0.25);\n      transition: opacity 0.18s, visibility 0.18s;\n      text-align: left;\n      pointer-events: none;\n    }\n\n    .tooltiptext::after {\n      content: \'\';\n      position: absolute;\n      top: 100%;\n      left: 50%;\n      transform: translateX(-50%);\n      border: 6px solid transparent;\n      border-top-color: var(--navy);\n    }\n\n    .tooltip:hover .tooltiptext {\n      visibility: visible;\n      opacity: 1;\n    }\n\n    .tooltiptext h3 {\n      font-family: \'Playfair Display\', serif !important;\n      font-size: 0.82rem !important;\n      font-weight: 700 !important;\n      color: var(--gold) !important;\n      background: none !important;\n      padding: 0 0 8px !important;\n      margin: 0 0 8px !important;\n      border-bottom: 1px solid rgba(201,168,76,0.2);\n      letter-spacing: 0 !important;\n      text-transform: none !important;\n      display: block !important;\n    }\n\n    .tooltiptext span[style] {\n      float: none !important;\n      width: auto !important;\n      display: inline-block;\n      font-size: 0.72rem;\n      color: var(--gold-light);\n      font-weight: 600;\n      min-width: 80px;\n    }\n\n    .tooltiptext br { display: block; margin-bottom: 4px; }\n\n    .tooltiptext p {\n      font-size: 0.78rem !important;\n      color: #b8c8e0 !important;\n      line-height: 1.8 !important;\n      margin: 0 !important;\n    }\n  </style>\n</head>\n<body>\n\n  %navbar%\n\n  <!-- HERO -->\n  <div class="hero">\n    <h1>Timetable Genie</h1>\n  </div>\n\n  <!-- MAIN -->\n  <main>\n\n    <!-- \u2550\u2550 PROGRAMMES \u2550\u2550 -->\n    <section id="programmes" class="section" style="scroll-margin-top: var(--nav-h)">\n      <div class="section-header">\n        <h2 class="section-title">Programmes</h2>\n      </div>\n      <div class="section-divider"></div>\n      <br/>\n      <div class="cards">\n\n        %programmes-divs%\n\n      </div>\n    </section>\n\n    <!-- \u2550\u2550 ACADEMICS \u2550\u2550 -->\n    <section id="academics" class="section" style="scroll-margin-top: var(--nav-h)">\n      <div class="section-header">\n        <h2 class="section-title">Academics</h2>\n      </div>\n      <div class="section-divider"></div>\n      <br/>\n      <div class="cards">\n\n        %academics-divs%\n\n      </div>\n    </section>\n\n    <!-- \u2550\u2550 LABS \u2550\u2550 -->\n    <section id="labs" class="section" style="scroll-margin-top: var(--nav-h)">\n      <div class="section-header">\n        <h2 class="section-title">Rooms &amp; Labs</h2>\n      </div>\n      <div class="section-divider"></div>\n      <br/>\n      <div class="cards">\n\n        %labs-divs%\n\n      </div>\n    </section>\n\n  </main>\n\n</body>\n</html>\n',"%navbar%",a8)
